"""matplotlib.colorizer — colorizer stubs (new in 3.9)."""

from matplotlib.cm import ScalarMappable, get_cmap
from matplotlib.colors import Normalize


class Colorizer:
    def __init__(self, cmap=None, norm=None):
        self.cmap = get_cmap(cmap) if isinstance(cmap, str) else cmap
        self.norm = norm or Normalize()

    def to_rgba(self, x, alpha=None, bytes=False):
        if self.cmap is None:
            self.cmap = get_cmap()
        normed = self.norm(x)
        return self.cmap(normed, alpha=alpha, bytes=bytes)
